    vector<pair<long long, long long>> segments;

    for (long long i = 0; i < nums.size(); ++i) {
        sum += nums[i];
        long long rem = (sum % k + k) % k;
        if (prefixRemainder.find(rem) != prefixRemainder.end()) {
            long long prev = prefixRemainder[rem];
            segments.emplace_back(prev + 1, i);
