fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut prefix_remainder = HashMap::new();
    prefix_remainder.insert(0, -1);
    let mut sum = 0;
    let mut segments = Vec::new();

    for i in 0..nums.len() {
        sum += nums[i];
        let rem = ((sum % k + k) % k) as i64;
        if let Some(&prev) = prefix_remainder.get(&rem) {
            segments.push((prev + 1, i as i64));
        }
        prefix_remainder.insert(rem, i as i64);
    }

    if segments.is_empty() {
        return nums.iter().sum();
    }

    segments.sort();
    let mut merged = Vec::new();
    for seg in segments {
        if merged.is_empty() || seg.0 > merged.last().unwrap().1 {
            merged.push(seg);
        } else {
            let last = merged.last_mut().unwrap();
            last.1 = last.1.max(seg.1);
        }
    }

    let mut total = 0;
    let mut last = 0;
    for seg in merged {
        for i in last..seg.0 {
            total += nums[i as usize];
        }
        last = seg.1 + 1;
    }
    for i in last..(nums.len() as i64) {
        total += nums[i as usize];
    }

    total
}
